-- HNSW 인덱스 재생성
DROP INDEX IF EXISTS gigacoffee.idx_products_embedding;
CREATE INDEX idx_products_embedding ON gigacoffee.products USING hnsw (embedding vector_cosine_ops) WITH (m = 16, ef_construction = 64);

-- 자연어 검색 함수
CREATE OR REPLACE FUNCTION gigacoffee.search_products_by_embedding(
  query_embedding vector(768),
  match_threshold float DEFAULT 0.5,
  match_count     int   DEFAULT 10
)
RETURNS TABLE (
  id uuid, category_id uuid, name text, price int,
  image_url text, description text, is_available boolean,
  options jsonb, created_at timestamptz, similarity float
)
LANGUAGE sql STABLE
SET search_path = gigacoffee, extensions, public
AS $$
  SELECT p.id, p.category_id, p.name, p.price, p.image_url,
         p.description, p.is_available, p.options, p.created_at,
         1 - (p.embedding <=> query_embedding) AS similarity
  FROM gigacoffee.products p
  WHERE p.is_available = true
    AND p.embedding IS NOT NULL
    AND 1 - (p.embedding <=> query_embedding) > match_threshold
  ORDER BY p.embedding <=> query_embedding
  LIMIT match_count;
$$;

GRANT EXECUTE ON FUNCTION gigacoffee.search_products_by_embedding TO anon, authenticated;